SELECT * FROM subscription_plan
 WHERE code = #{planCode}
   AND active = 1

SELECT * FROM subscription_benefit_policy
 WHERE plan_code = #{planCode}
   AND benefit_code = #{benefitCode}
   AND active = 1

SELECT * FROM ai_feature_benefit_policy
 WHERE feature_type = #{featureType}
   AND active = 1

mapper.update:
UPDATE user_subscription
   SET status = 'INACTIVE', canceled_at = #{now}
 WHERE user_id = #{userId} AND status = 'ACTIVE'

UPDATE users
   SET plan = #{planCode}
 WHERE id = #{userId}

mapper.select:
SELECT * FROM user_benefit_balance
 WHERE user_id = #{userId}
   AND period_start = #{periodStart}
   AND period_end = #{periodEnd}
 ORDER BY benefit_code ASC

SELECT * FROM user_benefit_balance
 WHERE user_id = #{userId}
   AND benefit_code = #{benefitCode}
   AND period_start = #{periodStart}

SELECT EXISTS (
    SELECT 1
      FROM benefit_transaction
     WHERE benefit_code = #{benefitCode}
       AND transaction_type = 'CONSUME'
       AND ref_type = #{refType}
       AND ref_id = #{refId}
)

SELECT * FROM benefit_transaction
 WHERE user_id = #{userId}
 ORDER BY id DESC
 LIMIT #{limit}

SELECT credit
  FROM users
 WHERE id = #{userId}

mapper.update:
UPDATE users
   SET credit = credit + #{creditAmount}
 WHERE id = #{userId}

mapper.select:
SELECT p.id, p.user_id, p.provider, p.product_code, p.amount, p.plan, p.credit_amount, p.status, p.paid_at, p.created_at, u.email AS user_email, u.name AS user_name FROM payment p LEFT JOIN users u ON u.id = p.user_id
p.status = #{status}
ORDER BY p.id DESC LIMIT 300
